def detect_auth_failures(trace):
    action_groups = trace.get('trace', {}).get('orchestrationTrace', {}).get('actionGroups', [])

    for ag in action_groups:
        if ag.get('type') == 'ACTION_GROUP_INVOCATION_FAILED':
            status_code = ag.get('statusCode')
            if status_code == 403:
                return {
                    'failure': True,
                    'reason': 'Lambda action group auth failure',
                    'actionGroup': ag.get('actionGroup'),
                    'lambdaArn': ag.get('functionSummary', {}).get('lambdaArn')
                }
    return {'failure': False}

