def check_kb_permissions(response, user_id):
    retrievals = response.get('trace', {}).get('retrievals', [])
    sensitive_indicators = ['ssn', 'credit_card', 'internal-only', f'tenant:{user_id}']

    for doc in retrievals:
        content = doc.get('content', {}).get('text', '').lower()
        for indicator in sensitive_indicators:
            if indicator in content and f'tenant:{user_id}' not in content:
                return {
                    'violation': True,
                    'type': 'CROSS_TENANT_KB_ACCESS',
                    'document': doc.get('location', {})
                }
    return {'violation': False}

import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({});

export async function detectSessionAuthDrift(sessionState: any, currentUserId: string) {
  const authContext = sessionState.sessionAttributes?.authContext;
  if (!authContext) return { drift: false };

  const expectedTenant = `tenant:${currentUserId}`;
  const actualTenant = authContext.tenantId;

  if (actualTenant !== expectedTenant) {
    return {
      drift: true,
      type: 'SESSION_AUTH_DRIFT',
      expected: expectedTenant,
      actual: actualTenant,
      sessionId: sessionState.sessionId
    };
  }

  return { drift: false };
}

